   649→		gc.ScrapeInterval = DefaultGlobalConfig.ScrapeInterval
   650→	}
   651→	if gc.ScrapeTimeout > gc.ScrapeInterval {
   652→		return errors.New("global scrape timeout greater than scrape interval")
   653→	}
   654→	if gc.ScrapeTimeout == 0 {
   655→		gc.ScrapeTimeout = min(DefaultGlobalConfig.ScrapeTimeout, gc.ScrapeInterval)
   656→	}
   657→	if gc.EvaluationInterval == 0 {
   658→		gc.EvaluationInterval = DefaultGlobalConfig.EvaluationInterval
   659→	}
   660→	if gc.ScrapeNativeHistograms == nil {
   661→		gc.ScrapeNativeHistograms = DefaultGlobalConfig.ScrapeNativeHistograms
   662→	}
   663→	if gc.ExtraScrapeMetrics == nil {
   664→		gc.ExtraScrapeMetrics = DefaultGlobalConfig.ExtraScrapeMetrics
   665→	}
   666→	if gc.ScrapeProtocols == nil {
   667→		if DefaultGlobalConfig.ScrapeProtocols != nil {
   668→			// This is the case where the defaults are set due to a feature flag.
   669→			// E.g. if the created-timestamp-zero-ingestion feature flag is
   670→			// used.
   671→			gc.ScrapeProtocols = DefaultGlobalConfig.ScrapeProtocols
   672→		}
   673→		// Otherwise, we leave ScrapeProtocols at nil for now. In the
   674→		// per-job scrape config, we have to recognize the unset case to
   675→		// correctly set the default depending on the local value of
   676→		// ScrapeNativeHistograms.
   677→	}
   678→	if gc.ScrapeProtocols != nil {
   679→		// Only validate if not-nil at this point.
   680→		if err := validateAcceptScrapeProtocols(gc.ScrapeProtocols); err != nil {
   681→			return fmt.Errorf("%w for global config", err)
   682→		}
   683→	}
   684→
   685→	*c = *gc
   686→	return nil
   687→}
