   883→// Validate validates scrape config, but also fills relevant default values from global config if needed.
   884→func (c *ScrapeConfig) Validate(globalConfig GlobalConfig) error {
   885→	if c == nil {
   886→		return errors.New("empty or null scrape config section")
   887→	}
   888→	// First set the correct scrape interval, then check that the timeout
   889→	// (inferred or explicit) is not greater than that.
   890→	if c.ScrapeInterval == 0 {
   891→		c.ScrapeInterval = globalConfig.ScrapeInterval
   892→	}
   893→	if c.ScrapeTimeout > c.ScrapeInterval {
   894→		return fmt.Errorf("scrape timeout greater than scrape interval for scrape config with job name %q", c.JobName)
   895→	}
   896→	if c.ScrapeTimeout == 0 {
   897→		c.ScrapeTimeout = min(globalConfig.ScrapeTimeout, c.ScrapeInterval)
   898→	}
   899→	if c.BodySizeLimit == 0 {
   900→		c.BodySizeLimit = globalConfig.BodySizeLimit
   901→	}
   902→	if c.SampleLimit == 0 {
   903→		c.SampleLimit = globalConfig.SampleLimit
   904→	}
   905→	if c.TargetLimit == 0 {
   906→		c.TargetLimit = globalConfig.TargetLimit
   907→	}
   908→	if c.LabelLimit == 0 {
   909→		c.LabelLimit = globalConfig.LabelLimit
   910→	}
   911→	if c.LabelNameLengthLimit == 0 {
   912→		c.LabelNameLengthLimit = globalConfig.LabelNameLengthLimit
   913→	}
   914→	if c.LabelValueLengthLimit == 0 {
   915→		c.LabelValueLengthLimit = globalConfig.LabelValueLengthLimit
   916→	}
   917→	if c.KeepDroppedTargets == 0 {
   918→		c.KeepDroppedTargets = globalConfig.KeepDroppedTargets
   919→	}
   920→	if c.ScrapeFailureLogFile == "" {
   921→		c.ScrapeFailureLogFile = globalConfig.ScrapeFailureLogFile
   922→	}
   923→	if c.ScrapeNativeHistograms == nil {
   924→		c.ScrapeNativeHistograms = globalConfig.ScrapeNativeHistograms
   925→	}
   926→	if c.ExtraScrapeMetrics == nil {
   927→		c.ExtraScrapeMetrics = globalConfig.ExtraScrapeMetrics
   928→	}
   929→
   930→	if c.ScrapeProtocols == nil {
   931→		switch {
   932→		case globalConfig.ScrapeProtocols != nil:
   933→			// global ScrapeProtocols either set explicitly or via a
   934→			// default triggered by a feature flag. This overrides
   935→			// the selection based on locally active scraping of
   936→			// native histograms.
   937→			c.ScrapeProtocols = globalConfig.ScrapeProtocols
   938→		case c.ScrapeNativeHistogramsEnabled():
   939→			c.ScrapeProtocols = DefaultProtoFirstScrapeProtocols
   940→		default:
   941→			c.ScrapeProtocols = DefaultScrapeProtocols
   942→		}
   943→	}
   944→	if err := validateAcceptScrapeProtocols(c.ScrapeProtocols); err != nil {
   945→		return fmt.Errorf("%w for scrape config with job name %q", err, c.JobName)
   946→	}
   947→
   948→	if c.ScrapeFallbackProtocol != "" {
   949→		if err := c.ScrapeFallbackProtocol.Validate(); err != nil {
   950→			return fmt.Errorf("invalid fallback_scrape_protocol for scrape config with job name %q: %w", c.JobName, err)
   951→		}
   952→	}
   953→
   954→	//nolint:staticcheck
   955→	if model.NameValidationScheme != model.UTF8Validation {
   956→		return errors.New("model.NameValidationScheme must be set to UTF8")
   957→	}
   958→
   959→	switch globalConfig.MetricNameValidationScheme {
   960→	case model.LegacyValidation, model.UTF8Validation:
   961→	default:
   962→		return errors.New("global name validation method must be set")
   963→	}
   964→	// Scrapeconfig validation scheme matches global if left blank.
   965→	localValidationUnset := false
   966→	switch c.MetricNameValidationScheme {
   967→	case model.UnsetValidation:
   968→		localValidationUnset = true
   969→		c.MetricNameValidationScheme = globalConfig.MetricNameValidationScheme
   970→	case model.LegacyValidation, model.UTF8Validation:
   971→	default:
   972→		return fmt.Errorf("unknown scrape config name validation method specified, must be either '', 'legacy' or 'utf8', got %s", c.MetricNameValidationScheme)
   973→	}
   974→
   975→	// Escaping scheme is based on the validation scheme if left blank.
   976→	switch globalConfig.MetricNameEscapingScheme {
   977→	case "":
   978→		if globalConfig.MetricNameValidationScheme == model.LegacyValidation {
   979→			globalConfig.MetricNameEscapingScheme = model.EscapeUnderscores
   980→		} else {
   981→			globalConfig.MetricNameEscapingScheme = model.AllowUTF8
   982→		}
   983→	case model.AllowUTF8, model.EscapeUnderscores, model.EscapeDots, model.EscapeValues:
   984→	default:
   985→		return fmt.Errorf("unknown global name escaping method specified, must be one of '%s', '%s', '%s', or '%s', got %q", model.AllowUTF8, model.EscapeUnderscores, model.EscapeDots, model.EscapeValues, globalConfig.MetricNameEscapingScheme)
   986→	}
   987→
   988→	// Similarly, if ScrapeConfig escaping scheme is blank, infer it from the
   989→	// ScrapeConfig validation scheme if that was set, or the Global validation
   990→	// scheme if the ScrapeConfig validation scheme was also not set. This ensures
   991→	// that local ScrapeConfigs that only specify Legacy validation do not inherit
   992→	// the global AllowUTF8 escaping setting, which is an error.
   993→	if c.MetricNameEscapingScheme == "" {
   994→		//nolint:gocritic
   995→		if localValidationUnset {
   996→			c.MetricNameEscapingScheme = globalConfig.MetricNameEscapingScheme
   997→		} else if c.MetricNameValidationScheme == model.LegacyValidation {
   998→			c.MetricNameEscapingScheme = model.EscapeUnderscores
   999→		} else {
  1000→			c.MetricNameEscapingScheme = model.AllowUTF8
  1001→		}
  1002→	}
  1003→
  1004→	switch c.MetricNameEscapingScheme {
  1005→	case model.AllowUTF8:
  1006→		if c.MetricNameValidationScheme != model.UTF8Validation {
  1007→			return errors.New("utf8 metric names requested but validation scheme is not set to UTF8")
  1008→		}
  1009→	case model.EscapeUnderscores, model.EscapeDots, model.EscapeValues:
  1010→	default:
  1011→		return fmt.Errorf("unknown scrape config name escaping method specified, must be one of '%s', '%s', '%s', or '%s', got %q", model.AllowUTF8, model.EscapeUnderscores, model.EscapeDots, model.EscapeValues, c.MetricNameEscapingScheme)
  1012→	}
  1013→
  1014→	if c.ConvertClassicHistogramsToNHCB == nil {
  1015→		global := globalConfig.ConvertClassicHistogramsToNHCB
  1016→		c.ConvertClassicHistogramsToNHCB = &global
  1017→	}
  1018→
  1019→	if c.AlwaysScrapeClassicHistograms == nil {
  1020→		global := globalConfig.AlwaysScrapeClassicHistograms
  1021→		c.AlwaysScrapeClassicHistograms = &global
  1022→	}
  1023→
  1024→	for _, rc := range c.RelabelConfigs {
  1025→		if err := rc.Validate(c.MetricNameValidationScheme); err != nil {
  1026→			return err
  1027→		}
  1028→	}
  1029→	for _, rc := range c.MetricRelabelConfigs {
  1030→		if err := rc.Validate(c.MetricNameValidationScheme); err != nil {
  1031→			return err
  1032→		}
  1033→	}
  1034→
  1035→	return nil
  1036→}
