  1043→// ToEscapingScheme wraps the equivalent common library function with the
  1044→// desired default behavior based on the given validation scheme. This is a
  1045→// workaround for third party exporters that don't set the escaping scheme.
  1046→func ToEscapingScheme(s string, v model.ValidationScheme) (model.EscapingScheme, error) {
  1047→	if s == "" {
  1048→		switch v {
  1049→		case model.UTF8Validation:
  1050→			return model.NoEscaping, nil
  1051→		case model.LegacyValidation:
  1052→			return model.UnderscoreEscaping, nil
  1053→		case model.UnsetValidation:
  1054→			return model.NoEscaping, fmt.Errorf("ValidationScheme is unset: %s", v)
  1055→		default:
  1056→			panic(fmt.Errorf("unhandled validation scheme: %s", v))
  1057→		}
  1058→	}
  1059→	return model.ToEscapingScheme(s)
  1060→}
